// Pull comments from YouTube/TikTok/Instagram for all published videos
const headers = { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}` };

// Get all published topics with YouTube video IDs
const topics = await this.helpers.httpRequest({
  method: 'GET',
  url: `${process.env.SUPABASE_URL}/rest/v1/topics?status=eq.published&youtube_video_id=not.is.null&select=id,project_id,youtube_video_id,seo_title`,
  headers,
});

let synced = 0;
for (const topic of (topics || [])) {
  // YouTube comments
  if (topic.youtube_video_id && process.env.YOUTUBE_API_KEY) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://www.googleapis.com/youtube/v3/commentThreads?part=snippet&videoId=${topic.youtube_video_id}&order=time&maxResults=20&key=${process.env.YOUTUBE_API_KEY}`,
      });

      for (const item of (resp?.items || [])) {
        const c = item.snippet.topLevelComment.snippet;
        const commentId = item.snippet.topLevelComment.id;

        // Check if already exists
        const existing = await this.helpers.httpRequest({
          method: 'GET',
          url: `${process.env.SUPABASE_URL}/rest/v1/comments?platform_comment_id=eq.${commentId}&select=id`,
          headers,
        });

        if (!existing || existing.length === 0) {
          await this.helpers.httpRequest({
            method: 'POST',
            url: `${process.env.SUPABASE_URL}/rest/v1/comments`,
            headers: { ...headers, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
            body: JSON.stringify({
              topic_id: topic.id,
              project_id: topic.project_id,
              platform: 'youtube',
              platform_comment_id: commentId,
              author: c.authorDisplayName,
              author_avatar_url: c.authorProfileImageUrl,
              text: c.textOriginal || c.textDisplay,
              like_count: c.likeCount || 0,
            }),
          });
          synced++;
        }
      }
    } catch (e) { /* continue with next topic */ }
  }
}

return [{ json: { synced, topics_checked: topics?.length || 0 } }];
